import datetime
from typing import Tuple

class AccountingSystem:
    def __init__(self, company_name: str, fiscal_year_start: Tuple[int, int]):
        self.company_name = company_name
        self.fiscal_year_start = fiscal_year_start
        self.transactions = []

    def add_transaction(self, date: datetime.date, description: str, amount: float, account: str):
        self.transactions.append({
            "date": date,
            "description": description,
            "amount": amount,
            "account": account
        })

    def generate_report(self, start_date: datetime.date, end_date: datetime.date):
        report = {
            "company_name": self.company_name,
            "start_date": start_date,
            "end_date": end_date,
            "accounts": {}
        }

        for transaction in self.transactions:
            if start_date <= transaction["date"] <= end_date:
                account = transaction["account"]
                if account not in report["accounts"]:
                    report["accounts"][account] = {
                        "debits": 0,
                        "credits": 0
                    }

                if transaction["amount"] >= 0:
                    report["accounts"][account]["debits"] += transaction["amount"]
                else:
                    report["accounts"][account]["credits"] += abs(transaction["amount"])

        return report

    def get_fiscal_year_start(self, date: datetime.date) -> datetime.date:
        year = date.year
        month, day = self.fiscal_year_start
        return datetime.date(year, month, day)

    def get_fiscal_year_end(self, date: datetime.date) -> datetime.date:
        fiscal_year_start = self.get_fiscal_year_start(date)
        return fiscal_year_start.replace(year=fiscal_year_start.year + 1) - datetime.timedelta(days=1)

    def get_fiscal_quarter(self, date: datetime.date) -> int:
        fiscal_year_start = self.get_fiscal_year_start(date)
        return (date.month - fiscal_year_start.month) // 3 + 1

